require"ExcelMgr"require"Taboo.WordTree"Taboo={}function Taboo:Init(a,b)local c={}setmetatable(c,self)self.__index=self;self.Inst=c;c:OnInit(a,b)return c end;function Taboo:OnInit(a,b)self.near_char_map=b;local d={}local e={}local f=#a;local g=Mathf.Ceil(f/1000)for h=1,g do TimeMgr.DelayFrame(h,function()local i=(h-1)*1000+1;local j=h*1000;for k=i,j do if k<=f then if a[k].near and a[k].near==1 then a[k].s=self:NormalizeStr(a[k].s)else a[k].s=self:RemoveBiaodian(a[k].s)end;if a[k].type and a[k].type==1 then table.insert(d,{s=a[k].s,id=k+3})else table.insert(e,{s=a[k].s,id=k+3})end end end;if h==g then self.tree_zixulie=WordTree:InitTree(d)self.tree_zichuan=WordTree:InitTree(e)end end)end end;function Taboo:FindNearChar(l)return self.near_char_map[l]or l end;function Taboo:RemoveBiaodian(m)if GameMgr.Inst.client_language~='chs_t'then return m end;local n=Tools.utf8ToNum('0')local o=Tools.utf8ToNum('a')m=string.lower(m)local p=''for h=1,Tools.GetStringLength(m)do local q=Tools.utf8ToNum(Tools.UTF8Sub(m,h,1))if q>256 or q>=o and q<o+26 or q>=n and q<n+10 then p=p..Tools.UTF8Sub(m,h,1)end end;return p end;function Taboo:NormalizeStr(m)local n=Tools.utf8ToNum('0')local o=Tools.utf8ToNum('a')m=string.lower(m)local p=''for h=1,Tools.GetStringLength(m)do local q=Tools.utf8ToNum(Tools.UTF8Sub(m,h,1))if q>256 or q>=o and q<o+26 or q>=n and q<n+10 then p=p..self:FindNearChar(Tools.UTF8Sub(m,h,1))end end;return p end;function Taboo:AddExtraWord(r,s)r=self:NormalizeStr(r)if not self:Test(r)then return true end;if s==1 then return self.tree_zixulie:AddExtraWord(r)else return self.tree_zichuan:AddExtraWord(r)end end;function Taboo:RemoveExtraWord(r,s)r=self:NormalizeStr(r)if not self:Test(r)then return true end;if s==1 then return self.tree_zixulie:RemoveExtraWord(r)else return self.tree_zichuan:RemoveExtraWord(r)end end;function Taboo:Test(m)m=self:RemoveBiaodian(m)local t=self:_test(m)if t then return t end;local u=self:NormalizeStr(m)if u~=m then t=self:_test(u)end;if t then return t end;if GamePlatformInfo.GetCurrentPlatform()=='AA32'and GameVersion.Fit('2.5.0')and not UnityEngine.Application.isEditor then t=LuaTools.TabooTest(m)if t then return t end end;return t end;function Taboo:_test(m)local t=nil;if self.tree_zichuan then t=self.tree_zichuan:TestZichuan(m)end;if t then return t end;if self.tree_zixulie then t=self.tree_zixulie:TestZixulie(m)end;return t end;return Taboo